import{_ as a,c as t,o as s,a1 as n}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Directory Structure Explained: Complete Factory Project Layout","description":"Learn the complete directory structure of AI App Factory and the purpose of each file. This tutorial explains core directories like agents, skills, policies, and artifacts to help you understand how Factory works, quickly locate and modify configuration files, and debug pipeline issues.","frontmatter":{"title":"Directory Structure Explained: Complete Factory Project Layout","sidebarTitle":"Directory Structure","subtitle":"Directory Structure Guide: Complete Factory Project Overview","description":"Learn the complete directory structure of AI App Factory and the purpose of each file. This tutorial explains core directories like agents, skills, policies, and artifacts to help you understand how Factory works, quickly locate and modify configuration files, and debug pipeline issues.","tags":["Appendix","Directory Structure","Project Architecture"],"prerequisite":["start-init-project"],"order":220},"headers":[],"relativePath":"hyz1992/agent-app-factory/appendix/directory-structure/index.md","filePath":"hyz1992/agent-app-factory/appendix/directory-structure/index.md"}'),i={name:"hyz1992/agent-app-factory/appendix/directory-structure/index.md"};function o(r,e,l,p,c,d){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="directory-structure-guide-complete-factory-project-overview" tabindex="-1">Directory Structure Guide: Complete Factory Project Overview <a class="header-anchor" href="#directory-structure-guide-complete-factory-project-overview" aria-label="Permalink to &quot;Directory Structure Guide: Complete Factory Project Overview&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>✅ Understand the complete directory structure of a Factory project</li><li>✅ Know the purpose of each directory and file</li><li>✅ Understand how artifacts are stored</li><li>✅ Master configuration file usage and modification methods</li></ul><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>Factory projects use a clear, layered directory structure that separates configuration, code, artifacts, and documentation. Understanding these directory structures helps you quickly locate files, modify configurations, and debug issues.</p><p>Factory projects have two forms:</p><p><strong>Form 1: Source Repository</strong> (cloned from GitHub) <strong>Form 2: Initialized Project</strong> (generated by <code>factory init</code>)</p><p>This tutorial focuses on <strong>Form 2</strong>—the initialized Factory project structure, as this is the directory you&#39;ll work with daily.</p><hr><h2 id="complete-factory-project-structure" tabindex="-1">Complete Factory Project Structure <a class="header-anchor" href="#complete-factory-project-structure" aria-label="Permalink to &quot;Complete Factory Project Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my-app/                          # Your Factory project root directory</span></span>
<span class="line"><span>├── .factory/                    # Factory core configuration directory (do not manually modify)</span></span>
<span class="line"><span>│   ├── pipeline.yaml             # Pipeline definition (7 stages)</span></span>
<span class="line"><span>│   ├── config.yaml               # Project configuration file (tech stack, MVP constraints, etc.)</span></span>
<span class="line"><span>│   ├── state.json                # Pipeline running state (current stage, completed stages)</span></span>
<span class="line"><span>│   ├── agents/                   # Agent definitions (AI assistant task descriptions)</span></span>
<span class="line"><span>│   ├── skills/                   # Skill modules (reusable knowledge)</span></span>
<span class="line"><span>│   ├── policies/                 # Policy documents (permissions, failure handling, code standards)</span></span>
<span class="line"><span>│   └── templates/                # Configuration templates (CI/CD, Git Hooks)</span></span>
<span class="line"><span>├── .claude/                      # Claude Code configuration directory (auto-generated)</span></span>
<span class="line"><span>│   └── settings.local.json       # Claude Code permission configuration</span></span>
<span class="line"><span>├── input/                        # User input directory</span></span>
<span class="line"><span>│   └── idea.md                   # Structured product idea (generated by Bootstrap)</span></span>
<span class="line"><span>└── artifacts/                    # Pipeline artifact directory (outputs from 7 stages)</span></span>
<span class="line"><span>    ├── prd/                      # PRD artifact</span></span>
<span class="line"><span>    │   └── prd.md                # Product Requirements Document</span></span>
<span class="line"><span>    ├── ui/                       # UI artifact</span></span>
<span class="line"><span>    │   ├── ui.schema.yaml        # UI structure definition</span></span>
<span class="line"><span>    │   └── preview.web/          # Previewable HTML prototype</span></span>
<span class="line"><span>    │       └── index.html</span></span>
<span class="line"><span>    ├── tech/                     # Tech artifact</span></span>
<span class="line"><span>    │   └── tech.md               # Technical architecture document</span></span>
<span class="line"><span>    ├── backend/                  # Backend code (Express + Prisma)</span></span>
<span class="line"><span>    │   ├── src/                  # Source code</span></span>
<span class="line"><span>    │   ├── prisma/               # Database configuration</span></span>
<span class="line"><span>    │   │   ├── schema.prisma     # Prisma data model</span></span>
<span class="line"><span>    │   │   └── seed.ts           # Seed data</span></span>
<span class="line"><span>    │   ├── tests/                # Tests</span></span>
<span class="line"><span>    │   ├── docs/                 # API documentation</span></span>
<span class="line"><span>    │   ├── package.json</span></span>
<span class="line"><span>    │   ├── tsconfig.json</span></span>
<span class="line"><span>    │   └── README.md</span></span>
<span class="line"><span>    ├── client/                   # Frontend code (React Native)</span></span>
<span class="line"><span>    │   ├── src/                  # Source code</span></span>
<span class="line"><span>    │   ├── __tests__/            # Tests</span></span>
<span class="line"><span>    │   ├── app.json</span></span>
<span class="line"><span>    │   ├── package.json</span></span>
<span class="line"><span>    │   └── README.md</span></span>
<span class="line"><span>    ├── validation/               # Validation artifact</span></span>
<span class="line"><span>    │   └── report.md             # Code quality validation report</span></span>
<span class="line"><span>    ├── preview/                  # Preview artifact</span></span>
<span class="line"><span>    │   ├── README.md             # Deployment and running guide</span></span>
<span class="line"><span>    │   └── GETTING_STARTED.md    # Quick start guide</span></span>
<span class="line"><span>    ├── _failed/                  # Failed artifact archive</span></span>
<span class="line"><span>    │   └── &lt;stage-id&gt;/           # Artifacts from failed stages</span></span>
<span class="line"><span>    └── _untrusted/               # Unauthorized artifact isolation</span></span>
<span class="line"><span>        └── &lt;stage-id&gt;/           # Files written by unauthorized agents</span></span></code></pre></div><hr><h2 id="factory-directory-explained" tabindex="-1">.factory/ Directory Explained <a class="header-anchor" href="#factory-directory-explained" aria-label="Permalink to &quot;.factory/ Directory Explained&quot;">​</a></h2><p>The <code>.factory/</code> directory is the core of the Factory project, containing pipeline definitions, Agent configurations, and policy documents. This directory is automatically created by the <code>factory init</code> command and typically doesn&#39;t need manual modification.</p><h3 id="pipeline-yaml-pipeline-definition" tabindex="-1">pipeline.yaml - Pipeline Definition <a class="header-anchor" href="#pipeline-yaml-pipeline-definition" aria-label="Permalink to &quot;pipeline.yaml - Pipeline Definition&quot;">​</a></h3><p><strong>Purpose</strong>: Defines the execution order, inputs/outputs, and exit criteria for the 7 stages.</p><p><strong>Key Content</strong>:</p><ul><li>7 stages: bootstrap, prd, ui, tech, code, validation, preview</li><li>For each stage: Agent, input files, output files</li><li>Exit criteria: validation standards for stage completion</li></ul><p><strong>Example</strong>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">stages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">bootstrap</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Initialize project idea</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    agent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">agents/bootstrap.agent.md</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    inputs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: []</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    outputs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">input/idea.md</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    exit_criteria</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">idea.md exists</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">idea.md describes a coherent product idea</span></span></code></pre></div><p><strong>When to modify</strong>: Typically no need to modify, unless you want to customize the pipeline flow.</p><h3 id="config-yaml-project-configuration-file" tabindex="-1">config.yaml - Project Configuration File <a class="header-anchor" href="#config-yaml-project-configuration-file" aria-label="Permalink to &quot;config.yaml - Project Configuration File&quot;">​</a></h3><p><strong>Purpose</strong>: Configures tech stack, MVP constraints, UI preferences, and other global settings.</p><p><strong>Main Configuration Items</strong>:</p><ul><li><code>preferences</code>: Tech stack preferences (backend language, database, frontend framework, etc.)</li><li><code>mvp_constraints</code>: MVP scope control (max pages, max models, etc.)</li><li><code>ui_preferences</code>: UI design preferences (aesthetic direction, color scheme)</li><li><code>pipeline</code>: Pipeline behavior (checkpoint mode, failure handling)</li><li><code>advanced</code>: Advanced options (Agent timeout, concurrency control)</li></ul><p><strong>Example</strong>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">preferences</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  backend</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    language</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">typescript</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    framework</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">express</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    database</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sqlite</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  mvp_constraints</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    max_pages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    enable_auth</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p><strong>When to modify</strong>: When you want to adjust the tech stack or change the MVP scope.</p><h3 id="state-json-pipeline-state" tabindex="-1">state.json - Pipeline State <a class="header-anchor" href="#state-json-pipeline-state" aria-label="Permalink to &quot;state.json - Pipeline State&quot;">​</a></h3><p><strong>Purpose</strong>: Records the pipeline&#39;s running state, supporting checkpoint resumption.</p><p><strong>Key Content</strong>:</p><ul><li><code>status</code>: Current status (idle/running/waiting_for_confirmation/paused/failed)</li><li><code>current_stage</code>: Current execution stage</li><li><code>completed_stages</code>: List of completed stages</li><li><code>last_updated</code>: Last update time</li></ul><p><strong>When to modify</strong>: Auto-updated, do not manually modify.</p><h3 id="agents-agent-definition-directory" tabindex="-1">agents/ - Agent Definition Directory <a class="header-anchor" href="#agents-agent-definition-directory" aria-label="Permalink to &quot;agents/ - Agent Definition Directory&quot;">​</a></h3><p><strong>Purpose</strong>: Defines the responsibilities, inputs/outputs, and execution constraints for each Agent.</p><p><strong>File List</strong>:</p><table tabindex="0"><thead><tr><th>File</th><th>Description</th></tr></thead><tbody><tr><td><code>orchestrator.checkpoint.md</code></td><td>Orchestrator core definition (pipeline coordination)</td></tr><tr><td><code>orchestrator-implementation.md</code></td><td>Orchestrator implementation guide (development reference)</td></tr><tr><td><code>bootstrap.agent.md</code></td><td>Bootstrap Agent (structured product idea)</td></tr><tr><td><code>prd.agent.md</code></td><td>PRD Agent (generate requirements document)</td></tr><tr><td><code>ui.agent.md</code></td><td>UI Agent (design UI prototype)</td></tr><tr><td><code>tech.agent.md</code></td><td>Tech Agent (design technical architecture)</td></tr><tr><td><code>code.agent.md</code></td><td>Code Agent (generate code)</td></tr><tr><td><code>validation.agent.md</code></td><td>Validation Agent (validate code quality)</td></tr><tr><td><code>preview.agent.md</code></td><td>Preview Agent (generate deployment guide)</td></tr></tbody></table><p><strong>When to modify</strong>: Typically no need to modify, unless you want to customize a specific Agent&#39;s behavior.</p><h3 id="skills-skill-module-directory" tabindex="-1">skills/ - Skill Module Directory <a class="header-anchor" href="#skills-skill-module-directory" aria-label="Permalink to &quot;skills/ - Skill Module Directory&quot;">​</a></h3><p><strong>Purpose</strong>: Reusable knowledge modules, each Agent loads corresponding Skill files.</p><p><strong>Directory Structure</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>skills/</span></span>
<span class="line"><span>├── bootstrap/skill.md         # Product idea structuring</span></span>
<span class="line"><span>├── prd/skill.md               # PRD generation</span></span>
<span class="line"><span>├── ui/skill.md                # UI design</span></span>
<span class="line"><span>├── tech/skill.md              # Technical architecture + database migrations</span></span>
<span class="line"><span>├── code/skill.md              # Code generation + tests + logging</span></span>
<span class="line"><span>│   └── references/            # Code generation reference templates</span></span>
<span class="line"><span>│       ├── backend-template.md   # Production-ready backend template</span></span>
<span class="line"><span>│       └── frontend-template.md  # Production-ready frontend template</span></span>
<span class="line"><span>└── preview/skill.md           # Deployment configuration + quick start guide</span></span></code></pre></div><p><strong>When to modify</strong>: Typically no need to modify, unless you want to extend a specific Skill&#39;s capabilities.</p><h3 id="policies-policy-document-directory" tabindex="-1">policies/ - Policy Document Directory <a class="header-anchor" href="#policies-policy-document-directory" aria-label="Permalink to &quot;policies/ - Policy Document Directory&quot;">​</a></h3><p><strong>Purpose</strong>: Defines policies for permissions, failure handling, code standards, etc.</p><p><strong>File List</strong>:</p><table tabindex="0"><thead><tr><th>File</th><th>Description</th></tr></thead><tbody><tr><td><code>capability.matrix.md</code></td><td>Capability boundary matrix (Agent read/write permissions)</td></tr><tr><td><code>failure.policy.md</code></td><td>Failure handling policy (retry, rollback, manual intervention)</td></tr><tr><td><code>context-isolation.md</code></td><td>Context isolation policy (save tokens)</td></tr><tr><td><code>error-codes.md</code></td><td>Unified error code standard</td></tr><tr><td><code>code-standards.md</code></td><td>Code standards (coding style, file structure)</td></tr><tr><td><code>pr-template.md</code></td><td>PR template and code review checklist</td></tr><tr><td><code>changelog.md</code></td><td>Changelog generation standard</td></tr></tbody></table><p><strong>When to modify</strong>: Typically no need to modify, unless you want to adjust policies or standards.</p><h3 id="templates-configuration-template-directory" tabindex="-1">templates/ - Configuration Template Directory <a class="header-anchor" href="#templates-configuration-template-directory" aria-label="Permalink to &quot;templates/ - Configuration Template Directory&quot;">​</a></h3><p><strong>Purpose</strong>: Configuration templates for CI/CD, Git Hooks, etc.</p><p><strong>File List</strong>:</p><table tabindex="0"><thead><tr><th>File</th><th>Description</th></tr></thead><tbody><tr><td><code>cicd-github-actions.md</code></td><td>CI/CD configuration (GitHub Actions)</td></tr><tr><td><code>git-hooks-husky.md</code></td><td>Git Hooks configuration (Husky)</td></tr></tbody></table><p><strong>When to modify</strong>: Typically no need to modify, unless you want to customize the CI/CD flow.</p><hr><h2 id="claude-directory-explained" tabindex="-1">.claude/ Directory Explained <a class="header-anchor" href="#claude-directory-explained" aria-label="Permalink to &quot;.claude/ Directory Explained&quot;">​</a></h2><h3 id="settings-local-json-claude-code-permission-configuration" tabindex="-1">settings.local.json - Claude Code Permission Configuration <a class="header-anchor" href="#settings-local-json-claude-code-permission-configuration" aria-label="Permalink to &quot;settings.local.json - Claude Code Permission Configuration&quot;">​</a></h3><p><strong>Purpose</strong>: Defines directories and operation permissions that Claude Code can access.</p><p><strong>When generated</strong>: Auto-generated during <code>factory init</code>.</p><p><strong>When to modify</strong>: Typically no need to modify, unless you want to adjust the permission scope.</p><hr><h2 id="input-directory-explained" tabindex="-1">input/ Directory Explained <a class="header-anchor" href="#input-directory-explained" aria-label="Permalink to &quot;input/ Directory Explained&quot;">​</a></h2><h3 id="idea-md-structured-product-idea" tabindex="-1">idea.md - Structured Product Idea <a class="header-anchor" href="#idea-md-structured-product-idea" aria-label="Permalink to &quot;idea.md - Structured Product Idea&quot;">​</a></h3><p><strong>Purpose</strong>: Stores structured product idea, generated by Bootstrap Agent.</p><p><strong>When generated</strong>: After Bootstrap stage completion.</p><p><strong>Content Structure</strong>:</p><ul><li>Problem definition</li><li>Target users</li><li>Core value</li><li>Assumptions</li><li>Out of scope</li></ul><p><strong>When to modify</strong>: If you want to adjust the product direction, you can manually edit it, then re-run Bootstrap or subsequent stages.</p><hr><h2 id="artifacts-directory-explained" tabindex="-1">artifacts/ Directory Explained <a class="header-anchor" href="#artifacts-directory-explained" aria-label="Permalink to &quot;artifacts/ Directory Explained&quot;">​</a></h2><p>The <code>artifacts/</code> directory is where pipeline artifacts are stored. Each stage writes artifacts to the corresponding subdirectory.</p><h3 id="prd-prd-artifact-directory" tabindex="-1">prd/ - PRD Artifact Directory <a class="header-anchor" href="#prd-prd-artifact-directory" aria-label="Permalink to &quot;prd/ - PRD Artifact Directory&quot;">​</a></h3><p><strong>Artifact Files</strong>:</p><ul><li><code>prd.md</code>: Product Requirements Document</li></ul><p><strong>Content</strong>:</p><ul><li>User stories</li><li>Features list</li><li>Non-functional requirements</li><li>Out of scope</li></ul><p><strong>When generated</strong>: After PRD stage completion.</p><h3 id="ui-ui-artifact-directory" tabindex="-1">ui/ - UI Artifact Directory <a class="header-anchor" href="#ui-ui-artifact-directory" aria-label="Permalink to &quot;ui/ - UI Artifact Directory&quot;">​</a></h3><p><strong>Artifact Files</strong>:</p><ul><li><code>ui.schema.yaml</code>: UI structure definition (pages, components, interactions)</li><li><code>preview.web/index.html</code>: Previewable HTML prototype</li></ul><p><strong>Content</strong>:</p><ul><li>Page structure (number of pages, layout)</li><li>Component definitions (buttons, forms, lists, etc.)</li><li>Interaction flows (navigation, transitions)</li><li>Design system (color scheme, fonts, spacing)</li></ul><p><strong>When generated</strong>: After UI stage completion.</p><p><strong>Preview method</strong>: Open <code>preview.web/index.html</code> in a browser.</p><h3 id="tech-tech-artifact-directory" tabindex="-1">tech/ - Tech Artifact Directory <a class="header-anchor" href="#tech-tech-artifact-directory" aria-label="Permalink to &quot;tech/ - Tech Artifact Directory&quot;">​</a></h3><p><strong>Artifact Files</strong>:</p><ul><li><code>tech.md</code>: Technical architecture document</li></ul><p><strong>Content</strong>:</p><ul><li>Tech stack selection (backend, frontend, database)</li><li>Data model design</li><li>API endpoint design</li><li>Security policies</li><li>Performance optimization recommendations</li></ul><p><strong>When generated</strong>: After Tech stage completion.</p><h3 id="backend-backend-code-directory" tabindex="-1">backend/ - Backend Code Directory <a class="header-anchor" href="#backend-backend-code-directory" aria-label="Permalink to &quot;backend/ - Backend Code Directory&quot;">​</a></h3><p><strong>Artifact Files</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>backend/</span></span>
<span class="line"><span>├── src/                      # Source code</span></span>
<span class="line"><span>│   ├── routes/               # API routes</span></span>
<span class="line"><span>│   ├── services/             # Business logic</span></span>
<span class="line"><span>│   ├── middleware/           # Middleware</span></span>
<span class="line"><span>│   └── utils/               # Utility functions</span></span>
<span class="line"><span>├── prisma/                   # Prisma configuration</span></span>
<span class="line"><span>│   ├── schema.prisma         # Prisma data model</span></span>
<span class="line"><span>│   └── seed.ts              # Seed data</span></span>
<span class="line"><span>├── tests/                    # Tests</span></span>
<span class="line"><span>│   ├── unit/                 # Unit tests</span></span>
<span class="line"><span>│   └── integration/          # Integration tests</span></span>
<span class="line"><span>├── docs/                     # Documentation</span></span>
<span class="line"><span>│   └── api-spec.yaml        # API specification (Swagger)</span></span>
<span class="line"><span>├── package.json</span></span>
<span class="line"><span>├── tsconfig.json</span></span>
<span class="line"><span>├── vitest.config.ts</span></span>
<span class="line"><span>└── README.md</span></span></code></pre></div><p><strong>Content</strong>:</p><ul><li>Express backend server</li><li>Prisma ORM (SQLite/PostgreSQL)</li><li>Vitest testing framework</li><li>Swagger API documentation</li></ul><p><strong>When generated</strong>: After Code stage completion.</p><h3 id="client-frontend-code-directory" tabindex="-1">client/ - Frontend Code Directory <a class="header-anchor" href="#client-frontend-code-directory" aria-label="Permalink to &quot;client/ - Frontend Code Directory&quot;">​</a></h3><p><strong>Artifact Files</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>client/</span></span>
<span class="line"><span>├── src/                      # Source code</span></span>
<span class="line"><span>│   ├── screens/              # Screens</span></span>
<span class="line"><span>│   ├── components/           # Components</span></span>
<span class="line"><span>│   ├── navigation/           # Navigation configuration</span></span>
<span class="line"><span>│   ├── services/             # API services</span></span>
<span class="line"><span>│   └── utils/               # Utility functions</span></span>
<span class="line"><span>├── __tests__/               # Tests</span></span>
<span class="line"><span>│   └── components/          # Component tests</span></span>
<span class="line"><span>├── assets/                  # Static assets</span></span>
<span class="line"><span>├── app.json                 # Expo configuration</span></span>
<span class="line"><span>├── package.json</span></span>
<span class="line"><span>├── tsconfig.json</span></span>
<span class="line"><span>└── README.md</span></span></code></pre></div><p><strong>Content</strong>:</p><ul><li>React Native + Expo</li><li>React Navigation</li><li>Jest + React Testing Library</li><li>TypeScript</li></ul><p><strong>When generated</strong>: After Code stage completion.</p><h3 id="validation-validation-artifact-directory" tabindex="-1">validation/ - Validation Artifact Directory <a class="header-anchor" href="#validation-validation-artifact-directory" aria-label="Permalink to &quot;validation/ - Validation Artifact Directory&quot;">​</a></h3><p><strong>Artifact Files</strong>:</p><ul><li><code>report.md</code>: Code quality validation report</li></ul><p><strong>Content</strong>:</p><ul><li>Dependency installation validation</li><li>TypeScript type checking</li><li>Prisma schema validation</li><li>Test coverage</li></ul><p><strong>When generated</strong>: After Validation stage completion.</p><h3 id="preview-preview-artifact-directory" tabindex="-1">preview/ - Preview Artifact Directory <a class="header-anchor" href="#preview-preview-artifact-directory" aria-label="Permalink to &quot;preview/ - Preview Artifact Directory&quot;">​</a></h3><p><strong>Artifact Files</strong>:</p><ul><li><code>README.md</code>: Deployment and running guide</li><li><code>GETTING_STARTED.md</code>: Quick start guide</li></ul><p><strong>Content</strong>:</p><ul><li>Local running steps</li><li>Docker deployment configuration</li><li>CI/CD pipeline</li><li>Access URLs and demo flow</li></ul><p><strong>When generated</strong>: After Preview stage completion.</p><h3 id="failed-failed-artifact-archive" tabindex="-1">_failed/ - Failed Artifact Archive <a class="header-anchor" href="#failed-failed-artifact-archive" aria-label="Permalink to &quot;_failed/ - Failed Artifact Archive&quot;">​</a></h3><p><strong>Purpose</strong>: Stores artifacts from failed stages for debugging.</p><p><strong>Directory Structure</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>_failed/</span></span>
<span class="line"><span>├── bootstrap/</span></span>
<span class="line"><span>├── prd/</span></span>
<span class="line"><span>├── ui/</span></span>
<span class="line"><span>├── tech/</span></span>
<span class="line"><span>├── code/</span></span>
<span class="line"><span>├── validation/</span></span>
<span class="line"><span>└── preview/</span></span></code></pre></div><p><strong>When generated</strong>: After a stage fails twice consecutively.</p><h3 id="untrusted-unauthorized-artifact-isolation" tabindex="-1">_untrusted/ - Unauthorized Artifact Isolation <a class="header-anchor" href="#untrusted-unauthorized-artifact-isolation" aria-label="Permalink to &quot;_untrusted/ - Unauthorized Artifact Isolation&quot;">​</a></h3><p><strong>Purpose</strong>: Stores files written by unauthorized agents to prevent contaminating main artifacts.</p><p><strong>Directory Structure</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>_untrusted/</span></span>
<span class="line"><span>├── bootstrap/</span></span>
<span class="line"><span>├── prd/</span></span>
<span class="line"><span>├── ui/</span></span>
<span class="line"><span>├── tech/</span></span>
<span class="line"><span>├── code/</span></span>
<span class="line"><span>├── validation/</span></span>
<span class="line"><span>└── preview/</span></span></code></pre></div><p><strong>When generated</strong>: When an agent attempts to write to an unauthorized directory.</p><hr><h2 id="common-questions" tabindex="-1">Common Questions <a class="header-anchor" href="#common-questions" aria-label="Permalink to &quot;Common Questions&quot;">​</a></h2><h3 id="_1-can-i-manually-modify-files-under-factory" tabindex="-1">1. Can I manually modify files under .factory/? <a class="header-anchor" href="#_1-can-i-manually-modify-files-under-factory" aria-label="Permalink to &quot;1. Can I manually modify files under .factory/?&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Caution When Modifying</p><p><strong>Not recommended</strong> to directly modify files under <code>.factory/</code> unless you are very clear about what you&#39;re doing. Incorrect modifications may cause the pipeline to fail to run normally.</p><p>If you need to customize configuration, prioritize modifying the <code>config.yaml</code> file.</p></div><h3 id="_2-can-i-manually-modify-files-under-artifacts" tabindex="-1">2. Can I manually modify files under artifacts/? <a class="header-anchor" href="#_2-can-i-manually-modify-files-under-artifacts" aria-label="Permalink to &quot;2. Can I manually modify files under artifacts/?&quot;">​</a></h3><p><strong>Yes</strong>. Files under <code>artifacts/</code> are pipeline output artifacts. You can:</p><ul><li>Modify <code>input/idea.md</code> or <code>artifacts/prd/prd.md</code> to adjust product direction</li><li>Manually fix code in <code>artifacts/backend/</code> or <code>artifacts/client/</code></li><li>Adjust styles in <code>artifacts/ui/preview.web/index.html</code></li></ul><p>After modification, you can re-run the pipeline from the corresponding stage.</p><h3 id="_3-how-to-handle-files-under-failed-and-untrusted" tabindex="-1">3. How to handle files under _failed/ and _untrusted/? <a class="header-anchor" href="#_3-how-to-handle-files-under-failed-and-untrusted" aria-label="Permalink to &quot;3. How to handle files under _failed/ and _untrusted/?&quot;">​</a></h3><ul><li><strong>_failed/</strong>: Check the failure cause, fix the issue, then re-run the stage.</li><li><strong>_untrusted/</strong>: Confirm if the file should exist. If so, move it to the correct directory.</li></ul><h3 id="_4-what-to-do-if-state-json-is-corrupted" tabindex="-1">4. What to do if state.json is corrupted? <a class="header-anchor" href="#_4-what-to-do-if-state-json-is-corrupted" aria-label="Permalink to &quot;4. What to do if state.json is corrupted?&quot;">​</a></h3><p>If <code>state.json</code> is corrupted, you can run the following command to reset:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span></span></code></pre></div><h3 id="_5-how-to-check-the-current-status-of-the-pipeline" tabindex="-1">5. How to check the current status of the pipeline? <a class="header-anchor" href="#_5-how-to-check-the-current-status-of-the-pipeline" aria-label="Permalink to &quot;5. How to check the current status of the pipeline?&quot;">​</a></h3><p>Run the following command to check the current status:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>In this lesson, we covered the complete directory structure of Factory projects in detail:</p><ul><li>✅ <code>.factory/</code>: Factory core configuration (pipeline, agents, skills, policies)</li><li>✅ <code>.claude/</code>: Claude Code permission configuration</li><li>✅ <code>input/</code>: User input (idea.md)</li><li>✅ <code>artifacts/</code>: Pipeline artifacts (prd, ui, tech, backend, client, validation, preview)</li><li>✅ <code>_failed/</code> and <code>_untrusted/</code>: Failed and unauthorized artifact archives</li></ul><p>Understanding these directory structures helps you quickly locate files, modify configurations, and debug issues.</p><hr><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../code-standards/">Code Standards</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>TypeScript coding standards</li><li>File structure and naming conventions</li><li>Comment and documentation requirements</li><li>Git commit message standards</li></ul></blockquote>`,147)])])}const g=a(i,[["render",o]]);export{h as __pageData,g as default};
